def contains_al_saf_without_sifa(norm):
    # find occurrences of 'الصف' followed by non 'ة' letter or end-of-word
    # But we want 'الصف' forming part of 'الصفوف' or 'الصف' or 'الصف الاول'
    # Accept 'الصف' plus any continuation except 'ة' to avoid 'صفة'
    return bool(re.search(r'الصف(?!ه|ة)[^\s]*', norm))

